mapper.select:
SELECT BACO.GATE_CD , BACO.BUYER_CD , BACO.BUYER_CD AS BUYER_CD_ORI , BACO.PUR_ORG_CD ,GETBUYERNAME(BACO.GATE_CD, BACO.BUYER_CD, #{ses.langCd}) AS BUYER_NM ,GETPURORGNAME(BACO.GATE_CD, BACO.BUYER_CD, BACO.PUR_ORG_CD, #{ses.langCd}) AS PUR_ORG_NM , BACO.CTRL_CD , BACO.CTRL_CD AS CTRL_CD_ORI , BACO.CTRL_NM , BACO.CTRL_NM_ENG , BACO.COMPANY_TYPE , BACO.CTRL_TYPE , BACO.USE_FLAG , 'U' AS INSERT_FLAG ,(SELECT COUNT(CTRL_CD) FROM STOCBAMT WHERE GATE_CD = BACO.GATE_CD AND BUYER_CD = BACO.BUYER_CD AND CTRL_CD = BACO.CTRL_CD AND DEL_FLAG = '0') AS MAPPING_ITEMS ,(SELECT COUNT(CTRL_CD) FROM STOCBACP WHERE GATE_CD = BACO.GATE_CD AND BUYER_CD = BACO.BUYER_CD AND CTRL_CD = BACO.CTRL_CD AND DEL_FLAG = '0') AS PIC_NUMBER , BACO.SORT_SQ FROM STOCBACO BACO JOIN STOCOGCM OGCM ON (BACO.GATE_CD = OGCM.GATE_CD AND BACO.BUYER_CD = OGCM.BUYER_CD AND OGCM.DEL_FLAG = '0') WHERE BACO.GATE_CD = #{ses.gateCd} AND BACO.DEL_FLAG = '0'
AND BACO.BUYER_CD = #{BUYER_CD}
AND BACO.CTRL_TYPE = #{CTRL_TYPE}
AND UPPER(BACO.CTRL_CD) LIKE '%' UPPER(#{CTRL_CD}) '%'
AND UPPER(BACO.CTRL_NM) LIKE '%' UPPER(#{CTRL_NM}) '%'
ORDER BY BACO.COMPANY_TYPE , BACO.CTRL_CD , BACO.SORT_SQ

