	, MOD_USER_ID
	, GATE_CD
	, BUYER_CD
	, CTRL_CD
	, CTRL_TYPE
	, CTRL_NM
	, CTRL_NM_ENG
	, PUR_ORG_CD
	, DEL_FLAG
	, USE_FLAG
	, SORT_SQ
	, COMPANY_TYPE
)
VALUES (
	  SYSDATE
	, #{ses.userId}
	, SYSDATE
	, #{ses.userId}
	, #{GATE_CD}
	, #{BUYER_CD}
	, #{CTRL_CD}
	, #{CTRL_TYPE}
	, #{CTRL_NM}
	, #{CTRL_NM_ENG}
	, #{PUR_ORG_CD}
	, '0'
	, #{USE_FLAG}
	, #{SORT_SQ}
	, #{COMPANY_TYPE}
)

