mapper.insert:
INSERT INTO STOCBACP (
	  REG_DATE
	, REG_USER_ID
	, MOD_DATE
	, MOD_USER_ID
	, GATE_CD
	, BUYER_CD
	, CTRL_CD
	, CTRL_USER_ID
	, DEL_FLAG
	, USE_FLAG
) SELECT
	  SYSDATE
	, #{ses.userId}
	, SYSDATE
	, #{ses.userId}
	, #{ses.gateCd}
	, #{BUYER_CD}
	, #{CTRL_CD}
	, #{CTRL_USER_ID}
	, '0'
	, #{USE_FLAG}
  FROM DUAL
  WHERE NOT EXISTS (
			SELECT '1' FROM STOCBACP
			WHERE GATE_CD  = #{ses.gateCd}
			  AND BUYER_CD = #{BUYER_CD}
			  AND CTRL_CD  = #{CTRL_CD}
			  AND CTRL_USER_ID = #{CTRL_USER_ID}
  		)

